type NeighborEntry = { cell: Cell; count: number; alive: boolean };

function neighborhoodOf(cells: Cell[]): Map<string, NeighborEntry> {
  const neighborhood = new Map<string, NeighborEntry>();
  const touch = (x: number, y: number): NeighborEntry => {
    const k = keyOf(x, y);
    const entry = neighborhood.get(k) ?? { cell: [x, y], count: 0, alive: false };
    neighborhood.set(k, entry);
    return entry;
  };
  for (const [x, y] of cells) {
    touch(x, y).alive = true;
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      touch(x + dx, y + dy).count++;
    }
  }
  return neighborhood;
}

export function nextGeneration(cells: Cell[]): Cell[] {
  const result: Cell[] = [];
  for (const { cell, count, alive } of neighborhoodOf(cells).values()) {
    if (survives(alive, count)) {
      result.push(cell);
    }
  }
  return result;
}
